use Text::CSV;

my $pdf = PDF::API2->open('example.pdf');
my $csv = Text::CSV->new({ binary => 1 });

my $page = $pdf->page(1);
my $content = $page->content;

my @rows;
while ($content =~ /([0-9]{4}-[0-9]{2}-[0-9]{2})|([^:]+:[^:]+:)/g) {
    push @rows, [ $1, $2 ];
}

open my $fh, '>', 'output.csv' or die "Could not open file 'output.csv' $!";
$csv->print($fh, $_) for @rows;
close $fh;

print "Data extracted and saved to output.csv\n";
